import React, { useState } from "react";
import { Row, Col, Form, Button, Alert } from "react-bootstrap";
import { dummyQuestionsAndAnswers } from "../utilis/dummy";

function FormInputs({ addQuestionAndAnswer }) {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");

  const handleAddQuestionAndAnswer = () => {
    if (question === "" || answer === "") {
      // alert('يجب أن يكون لديك سؤال وإجابة')
      return (
        <Alert variant="danger">
          <Alert.Heading>Oh snap! You got an error!</Alert.Heading>
          <p>
            Change this and that and try again. Duis mollis, est non commodo
            luctus, nisi erat porttitor ligula, eget lacinia odio sem nec elit.
            Cras mattis consectetur purus sit amet fermentum.
          </p>
        </Alert>
      );
    } else {
      dummyQuestionsAndAnswers.push({
        id: Math.random() * 1000000,
        question: question,
        answer: answer,
      });
      setQuestion("");
      setAnswer("");
      addQuestionAndAnswer();
    }
  };

  const handleQuestionChange = (e) => {
    setQuestion(e.target.value);
  };
  const handleAnswerChange = (e) => {
    setAnswer(e.target.value);
  };
  return (
    <Row className="my-2">
      <Col sm="5">
        <Form.Control
          onChange={handleQuestionChange}
          value={question}
          type="text"
          placeholder="اكتب سؤالك هنا ثم اضغط على إضافة"
        />
      </Col>
      <Col sm="5">
        <Form.Control
          onChange={handleAnswerChange}
          value={answer}
          type="text"
          placeholder="اكتب الإجابة هنا"
        />
      </Col>
      <Col sm="2">
        <button
          className="btn-color"
          onClick={handleAddQuestionAndAnswer}
          type="submit"
        >
          إضافة
        </button>
      </Col>
    </Row>
  );
}

export default FormInputs;
